import { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../context/AuthContext';

export default function Login() {
  const [form, setForm] = useState({ email: '', password: '' });
  const [loading, setLoading] = useState(false);
  const { login } = useAuth();
  const navigate = useNavigate();

  const handleChange = e => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const user = await login(form.email, form.password);
      toast.success(`Welcome back, ${user.name}!`);
      navigate(`/${user.role}`);
    } catch (err) {
      toast.error(err.response?.data?.message || 'Login failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center px-4" style={{ background: '#0a0d1a' }}>
      <div style={{ background: '#111827', border: '1px solid #1f2937', width: '100%', maxWidth: 420 }}
           className="p-8 rounded-2xl">
        <h1 style={{ fontFamily: 'Syne, sans-serif' }} className="text-2xl font-bold mb-1">Sign In</h1>
        <p className="text-gray-400 text-sm mb-8">Access your BackerSphere X account</p>

        <form onSubmit={handleSubmit} className="space-y-5">
          <div>
            <label className="block text-sm text-gray-400 mb-1.5">Email</label>
            <input name="email" type="email" value={form.email} onChange={handleChange} required
              style={{ background: '#0a0d1a', border: '1px solid #374151', color: 'white' }}
              className="w-full px-4 py-3 rounded-xl text-sm focus:outline-none focus:border-teal-500 transition-colors"
              placeholder="you@example.com" />
          </div>
          <div>
            <label className="block text-sm text-gray-400 mb-1.5">Password</label>
            <input name="password" type="password" value={form.password} onChange={handleChange} required
              style={{ background: '#0a0d1a', border: '1px solid #374151', color: 'white' }}
              className="w-full px-4 py-3 rounded-xl text-sm focus:outline-none focus:border-teal-500 transition-colors"
              placeholder="••••••••" />
          </div>
          <button type="submit" disabled={loading}
            style={{ background: '#00d4aa', color: '#0a0d1a' }}
            className="w-full py-3 rounded-xl font-bold text-sm hover:opacity-90 transition-all disabled:opacity-60">
            {loading ? 'Signing in...' : 'Sign In'}
          </button>
        </form>

        <p className="text-center text-gray-500 text-sm mt-6">
          No account?{' '}
          <Link to="/register" style={{ color: '#00d4aa' }} className="hover:underline">Register</Link>
        </p>
        <p className="text-center text-gray-600 text-xs mt-3">
          <Link to="/admin/login" className="hover:text-gray-400 transition-colors">Admin Login →</Link>
        </p>
      </div>
    </div>
  );
}
